@Override
    public void start() {
        scheduledExecutor.schedule(
            scanResumeJob,
            0L,
            TimeUnit.MILLISECONDS
        );

        scheduledExecutor.scheduleAtFixedRate(
            beaconsEvictionJob,
            scanDuration.scanDurationMillis,
            BEACON_EVICTION_PERIODICITY_MILLIS,
            TimeUnit.MILLISECONDS
        );
    }
